class Solution:
    def numberOfSpecialChars(self, word: str) -> int:
        last_lowercase = {}
        first_uppercase = {}
        for i, char in enumerate(word):
            if char.islower() and char not in last_lowercase:
                last_lowercase[char] = i
            if char.isupper() and char.lower() not in first_uppercase:
                first_uppercase[char.lower()] = i
        count = 0
        for char in last_lowercase:
            if char in first_uppercase and last_lowercase[char] < first_uppercase[char]:
                count += 1
        return count
```
